exercises.solution:
DURATIONS = {'H': 100, 'CX': 300, 'X': 100}

def schedule_asap(gates):
    qubit_available = {}
    scheduled = []

    for name, qubits in gates:
        # Find earliest start
        start = 0
        for q in qubits:
            if q in qubit_available:
                start = max(start, qubit_available[q])

        scheduled.append((name, qubits, start))

        # Update availability
        duration = DURATIONS.get(name, 100)
        end = start + duration
        for q in qubits:
            qubit_available[q] = end

    return scheduled

gates = [('H', (0,)), ('H', (1,)), ('CX', (0, 1)), ('X', (0,))]
scheduled = schedule_asap(gates)
for g in scheduled:
    print(f"{g[0]}({g[1]}): t={g[2]}")

def find_gaps(busy_intervals, total_time):
    gaps = []
    current = 0

    for start, end in busy_intervals:
        if start > current:
            gaps.append((current, start))
        current = max(current, end)

    if current < total_time:
        gaps.append((current, total_time))

    return gaps

busy = [(0, 100), (200, 400), (500, 600)]
gaps = find_gaps(busy, 800)
print(f"Gaps: {gaps}")
